```hcl
# Terraform configuration for GCP infrastructure with VPC, instances, MIG, and global load balancer

terraform {
  required_version = ">= 1.0"
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

provider "google" {
  project = var.project_id
  region  = var.region
}

# Variables
variable "project_id" {
  description = "GCP Project ID"
  type        = string
}

variable "region" {
  description = "GCP Region"
  type        = string
  default     = "us-central1"
}

# Enable required APIs
resource "google_project_service" "compute_api" {
  service = "compute.googleapis.com"
  project = var.project_id
}

resource "google_project_service" "compute_beta_api" {
  service = "compute.googleapis.com"
  project = var.project_id
  disable_dependent_services = true
}

resource "google_project_service" "cloudbilling_api" {
  service = "cloudbilling.googleapis.com"
  project = var.project_id
}

# VPC Network
resource "google_compute_network" "vpc" {
  name                    = "app-vpc"
  auto_create_subnetworks = false
  depends_on              = [google_project_service.compute_api]
}

# Subnets
resource "google_compute_subnetwork" "subnet" {
  name          = "app-subnet"
  ip_cidr_range = "10.0.1.0/24"
  region        = var.region
  network       = google_compute_network.vpc.id
}

# Firewall rules
resource "google_compute_firewall" "allow_http" {
  name    = "allow-http"
  network = google_compute_network.vpc.name

  allow {
    protocol = "tcp"
    ports    = ["80", "8080"]
  }

  source_ranges = ["0.0.0.0/0"]
  target_tags   = ["http-server"]
}

resource "google_compute_firewall" "allow_ssh" {
  name    = "allow-ssh"
  network = google_compute_network.vpc.name

  allow {
    protocol = "tcp"
    ports    = ["22"]
  }

  source_ranges = ["0.0.0.0/0"]
}

# NAT Router
resource "google_compute_router" "nat_router" {
  name    = "nat-router"
  region  = var.region
  network = google_compute_network.vpc.id
}

resource "google_compute_router_nat" "nat" {
  name                               = "nat-gateway"
  router                             = google_compute_router.nat_router.name
  region                             = var.region
  nat_ip_allocate_option             = "AUTO_ONLY"
  source_subnetwork_ip_ranges_to_nat = "ALL_SUBNETWORKS_ALL_IP_RANGES"
}

# Startup script for instances
data "template_file" "startup_script" {
  template = file("${path.module}/startup-script.sh")
}

# Instance template
resource "google_compute_instance_template" "instance_template" {
  name_prefix  = "app-template-"
  machine_type = "e2-medium"

  network_interface {
    network    = google_compute_network.vpc.id
    subnetwork = google_compute_subnetwork.subnet.id
    access_config {
    }
  }

  disk {
    boot         = true
    source_image = "projects/debian-cloud/global/images/family/debian-11"
    auto_delete  = true
  }

  metadata_startup_script = data.template_file.startup_script.rendered

  tags = ["http-server"]

  lifecycle {
    create_before_destroy = true
  }
}

# Health check
resource "google_compute_health_check" "health_check" {
  name = "app-health-check"

  http_health_check {
    port         = 80
    request_path = "/"
  }
}

# Instance group manager (regional)
resource "google_compute_region_instance_group_manager" "instance_group_manager" {
  name               = "app-group-manager"
  base_instance_name = "app-vm"
  region             = var.region
  version {
    name              = "v1"
    instance_template = google_compute_instance_template.instance_template.id
  }

  named_port {
    name = "http"
    port = 80
  }

  auto_healing_policies {
    health_check      = google_compute_health_check.health_check.id
    initial_delay_sec = 60
  }
}

# Backend service for HTTP load balancer
resource "google_compute_region_backend_service" "backend_service" {
  name                  = "app-backend"
  region                = var.region
  protocol              = "HTTP"
  load_balancing_scheme = "EXTERNAL_MANAGED"
  timeout_sec           = 30
  session_affinity      = "NONE"

  backend {
    group                 = google_compute_region_instance_group_manager.instance_group_manager.instance_group
    balancing_mode        = "RATE"
    max_rate_per_instance = 100
  }

  health_checks = [google_compute_health_check.health_check.id]
}

# URL Map
resource "google_compute_url_map" "url_map" {
  name            = "app-url-map"
  default_service = google_compute_region_backend_service.backend_service.id
}

# Target HTTP proxy
resource "google_compute_target_http_proxy" "http_proxy" {
  name    = "app-http-proxy"
  url_map = google_compute_url_map.url_map.id
}

# Global forwarding rule
resource "google_compute_global_forwarding_rule" "forwarding_rule" {
  name       = "app-forwarding-rule"
  target     = google_compute_target_http_proxy.http_proxy.id
  port_range = "80"
  ip_protocol = "TCP"
}

# Reserve global static IP for load balancer
resource "google_compute_global_address" "lb_ip" {
  name = "app-lb-ip"
}

# Output the load balancer IP
output "load_balancer_ip" {
  value = google_compute_global_address.lb_ip.address
}
```

Create a `startup-script.sh` file in the same directory:

```bash
#!/bin/bash
apt-get update
apt-get install -y apache2
systemctl start apache2
systemctl enable apache2
echo "<h1>Terraform GCP Load Balancer Demo</h1>" > /var/www/html/index.html
```

**Usage:**
```bash
terraform init
terraform plan -var="project_id=your-project-id" -var="region=us-central1"
terraform apply -var="project_id=your-project-id" -var="region=us-central1"
```

This configuration creates:
- VPC network and subnet
- Firewall rules for HTTP/SSH
- NAT router for outbound internet
- Instance template with startup script
- Regional instance group manager with auto-healing
- HTTP health check
- Global HTTP load balancer with static IP
- All required GCP APIs enabled

